import React, { useState, useEffect, useCallback } from 'react';
import { useSupabase } from '../context/SupabaseContext';
import { useToast } from '../context/ToastContext';
import { Button, Badge, Spinner, EmptyState, Modal, Field, inputStyle, selectStyle } from '../components/ui';
import { fmtDate } from '../lib/utils';

export default function UsersPage() {
  const { client } = useSupabase();
  const { addToast } = useToast();
  const [users, setUsers]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal]   = useState(null);
  const [form, setForm]     = useState({ role:'staff', status:'approved' });
  const [saving, setSaving] = useState(false);

  const load = useCallback(async () => {
    setLoading(true);
    const { data } = await client.from('profiles').select('*').order('created_at',{ascending:false});
    setUsers(data||[]);
    setLoading(false);
  }, [client]);

  useEffect(() => { load(); }, [load]);

  const handleSave = async () => {
    setSaving(true);
    const { error } = await client.from('profiles').update({ role:form.role, status:form.status }).eq('id',modal.id);
    setSaving(false);
    if (error) { addToast(error.message,'error'); return; }
    addToast('User updated'); setModal(null); load();
  };

  const pending = users.filter(u=>u.status==='pending').length;

  if (loading) return <Spinner />;

  return (
    <div>
      <div className="page-header"><h1>Users & Roles</h1><p>Manage system access and permissions</p></div>
      {pending>0&&<div style={{ padding:'12px 16px', background:'#FFFBEB', border:'1px solid #FCD34D', borderRadius:10, marginBottom:16, fontSize:13, fontWeight:600, color:'#92400E' }}>⏳ {pending} user{pending>1?'s':''} pending approval</div>}
      <div className="card">
        {users.length===0 ? <EmptyState icon="🔐" message="No users found" /> : (
          <table>
            <thead><tr><th>Name</th><th>Email</th><th>Role</th><th>Status</th><th>Joined</th><th>Actions</th></tr></thead>
            <tbody>{users.map(u=>(
              <tr key={u.id}>
                <td style={{ fontWeight:700 }}>{u.full_name||'—'}</td>
                <td style={{ fontSize:12, color:'var(--text3)' }}>{u.email||'—'}</td>
                <td><Badge color={u.role==='admin'?'purple':u.role==='manager'?'blue':'gray'}>{u.role}</Badge></td>
                <td><Badge color={u.status==='approved'?'green':u.status==='pending'?'yellow':'red'}>{u.status}</Badge></td>
                <td style={{ fontSize:12, color:'var(--text3)' }}>{fmtDate(u.created_at)}</td>
                <td><button className="action-btn" onClick={()=>{setForm({role:u.role,status:u.status});setModal(u);}}>Edit</button></td>
              </tr>
            ))}</tbody>
          </table>
        )}
      </div>
      {modal && (
        <Modal title={`Edit — ${modal.full_name||modal.email}`} onClose={()=>setModal(null)}>
          <div className="form-grid">
            <Field label="Role"><select style={selectStyle} value={form.role} onChange={e=>setForm(f=>({...f,role:e.target.value}))}><option value="admin">Admin</option><option value="manager">Manager</option><option value="staff">Staff</option><option value="viewer">Viewer</option></select></Field>
            <Field label="Status"><select style={selectStyle} value={form.status} onChange={e=>setForm(f=>({...f,status:e.target.value}))}><option value="approved">Approved</option><option value="pending">Pending</option><option value="rejected">Rejected</option></select></Field>
          </div>
          <div style={{ display:'flex', gap:10, marginTop:20 }}>
            <Button variant="secondary" onClick={()=>setModal(null)}>Cancel</Button>
            <Button onClick={handleSave} disabled={saving}>{saving?'Saving…':'Update User'}</Button>
          </div>
        </Modal>
      )}
    </div>
  );
}
